#include <bits/stdc++.h>using namespace std; int main(){    int t;    cin>>t;    while(t--){         int n;    cin>>n;    vector<int>a(n);     for(int i=0;i<n;i++){        cin>>a[i];    }    long long ans =-1;    for(int d=1;d<=n;++d){        if(n%d==0){            long long mx=-1e18;            long long mn=1e18;             for(int i=0;i<n;i+=d){                long long sm=0;                 for(int j=i;j<i+d;++j){                    sm += a[j];                }                mx = max(mx, sm);                 mn = min(mn,sm);             }            ans = max(ans, mx-mn);                    }    }    cout<<ans<<endl;}}